ll dis[55][5050];
struct node {
	ll id, coin, d;
	bool operator<(const node& a)const {
		return a.d < d;
	}
};
void solve(int CASE)
{
	fa(i, 1, 50)fa(j, 0, 5000)dis[i][j] = LNF;
	ll n, m, s; cin >> n >> m >> s;
	if (s >= 5000)s = 5000;
	var g = vector<vector<tuple<ll, ll, ll>>>(n + 1);
	fa(i, 1, m) {
		ll u, v, x, t; cin >> u >> v >> x >> t;
		g[u].pb({ v,x,t }), g[v].pb({ u,x,t });
	}
	var p = vector<pll>(n + 1);
	fa(i, 1, n)cin >> p[i].px >> p[i].py;
	var Q = priority_queue<node>();
	Q.push({ 1,s,dis[1][s] = 0 });
	while (Q.size()) {
		var[now, coin, d] = Q.top();
		Q.pop();
		if (d > dis[now][coin])continue;

		// 只处理一次，松弛
		const var& [c, w] = p[now];
		if (coin + c <= 5000 and
			dis[now][coin + c] > dis[now][coin] + w) {
			dis[now][coin + c] = dis[now][coin] + w;
			Q.push({ now, coin + c, dis[now][coin + c] });
		}

		for (const var& [to, c, w] : g[now]) {
			if (coin >= c and
				dis[to][coin - c] > dis[now][coin] + w) {
				dis[to][coin - c] = dis[now][coin] + w;
				Q.push({ to, coin - c, dis[to][coin - c] });
			}
		}
	}
	fa(i, 2, n) {
		ll ans = LNF;
		fa(j, 0, 5000)ans = min(ans, dis[i][j]);
		cout << ans << endl;
	}
	return;
}
